+        ])
+        .unwrap();
+        let target = MultiIndex::from_tuples(vec![vec!["a".into()], vec!["b".into()]]).unwrap();
+
+        let (indexer, missing) = source.get_indexer_non_unique(&target);
+        assert_eq!(indexer, vec![-1, -1]);
+        assert_eq!(missing, vec![0, 1]);
